mapper.insert:
 		INSERT INTO
 		XBOLTADM.TB_CHANGE_SET(
 			ChangeSetID
 			,ProjectID
 			,PJTcategory
 			,ItemID
 			,ItemClassCode

 			,ItemTypeCode
 			,AuthorID
 			,AuthorName
 			,AuthorTeamID
 			,CompanyID

 			,Description
 			
 			,ChangeType
 			,Reason
 			,FromOrg
 			,ToOrg
 			,Status
 			,CreationTime
 		)VALUES(
 			#{ChangeSetID}
 			,#{ProjectID}
 			,#{PJTcategory}
 			,#{ItemID}
 			,(Select ClassCode FROM XBOLTADM.TB_ITEM WHERE ItemID = #{ItemID})

 			,(Select ItemTypeCode FROM XBOLTADM.TB_ITEM WHERE ItemID = #{ItemID})
 			,#{AuthorID}
 			,#{AuthorName}
 			,#{TeamID}
 			,#{CompanyID}

 			,#{Description}
 			
 			,#{ChangeType}
 			,#{Reason}
 			,#{FromOrg}
 			,#{ToOrg}
 			,#{Status}
 			,getDate()
		)

mapper.select:
SELECT TCS.ChangeSetID , TIA.PlainText AS Name , TDS.Name AS StatusName , TDR.Name AS Reason , TDC.Name AS ChangeType , TDCT.Name AS Category , TCS.AuthorName , TTC.Name AS CompanyName , TTT.Name AS TeamName , TCS.Description , CONVERT(varchar(14),TCS.CreationTime,111) as CreationTime , XBOLTADM.fn_GetMyAbsPathForList(TCS.ItemID, #{languageID}) AS Path , TI.Status AS ItemStatus , TCS.ItemID , ISNULL(TCS.FromItemID,'') AS FromItemID , ISNULL(TCS.ToItemID,'') AS ToItemID , TCS.Status , TCS.AuthorID , TCS.Approver , TI.Identifier , TCS.Reason As ReasonId , TCS.Description , TCS.ProjectID FROM XBOLTADM.TB_CHANGE_SET TCS
Left Outer Join XBOLTADM.TB_ITEM TI on TCS.ItemID = TI.ItemID
Left Outer Join XBOLTADM.TB_ITEM_ATTR TIA on TCS.ItemID = TIA.ItemID AND TIA.AttrTypeCode = 'AT00001' AND TIA.LanguageID = #{languageID} Left Outer Join XBOLTADM.TB_DICTIONARY TDS on TCS.Status = TDS.TypeCode AND TDS.Category = 'CNGSTS' AND TDS.LanguageID = #{languageID} Left Outer Join XBOLTADM.TB_DICTIONARY TDR on TCS.Reason = TDR.TypeCode AND TDR.Category = 'CR' AND TDR.LanguageID = #{languageID} Left Outer Join XBOLTADM.TB_DICTIONARY TDC on TCS.ChangeType = TDC.TypeCode AND TDC.Category = 'CNGT1' AND TDC.LanguageID = #{languageID} Left Outer Join XBOLTADM.TB_DICTIONARY TDCT on TCS.PJTCategory = TDCT.TypeCode AND TDCT.Category = 'PJTCAT' AND TDCT.LanguageID = #{languageID} Left Outer Join XBOLTADM.TB_TEAM_TXT TTT on TCS.AuthorTeamID = TTT.TeamID AND TTT.LanguageID = #{languageID} Left Outer Join XBOLTADM.TB_TEAM_TXT TTC on TCS.CompanyID = TTC.TeamID AND TTC.LanguageID = #{languageID} WHERE TCS.ChangeSetID = #{s_itemID}

SELECT 
	Count(*)
FROM 
	XBOLTADM.TB_CHANGE_SET TCS

	
		TCS.ProjectID = #{projectID}
	
	
		AND TCS.ItemTypeCode = #{ItemTypeCode}
	
	
		AND TCS.ChangeType = #{changeClassList}
	
	
		AND TCS.Status = #{Status}
	
	
		AND TCS.AuthorTeamID = #{AuthorTeamID}
	
	
		AND TCS.PJTCategory = #{category}
	
	
		AND TCS.AuthorID = #{AuthorID}
	
	
		AND TIA.PlainText Like '%'+#{searchValue}+'%'
	
	
		CONVERT(VARCHAR, TCS.CreationTime, 120) BETWEEN #{SC_STR_DT} AND #{SC_END_DT}

  	SELECT 
		*
	FROM(	
		SELECT	
		    TOP 1000 Row_Number()OVER(		
			
				
					Order by ${orderOption}
				
				
					Order by ChangeSetID DESC
				
			
		   ) as RNUM
		 , 0 AS CHK  
 		 , TCS.ChangeSetID
 		 , TCS.ProjectID
 		 , TI.Identifier
		 , TIA.PlainText AS ItemName
		 , TCS.ItemID
		 , TCTS.Name AS  ChangeType
		 , TD.Name AS ClassCode
		 , TDT.Name AS TypeCode
		 , TRS.Name AS Reason
		 , TCS.Description
		 , ISNULL(TTT.Name,'') AS TeamName
		 , TCS.AuthorID
		 , ISNULL(TM.Name,'') + Case When ISNULL(TM.NameEN,'') != '' Then '(' + ISNULL(TM.NameEN,'') + ')' Else '' End As AuthorName  
		 , ISNULL(CONVERT(char(10),TCS.CreationTime, 120),'') as CreationTime
		 , ISNULL(CONVERT(char(10),TCS.ApproveDate, 120),'') as ApproveDate
		 , ISNULL(CONVERT(char(10),TCS.CompletionDT, 120),'') as CompletionDT
		 , CASE ISNULL(TCS.CompletionDT, '') WHEN '' THEN '' ELSE '~' END CompletionDTYNMark
		 , TCS.Status as StatusCode
		 ,TDS.Name AS StatusName
		 , TI.Status AS ItemStatus
		 , TDIS.Name AS ItemStatusName
		 , ISNULL(CONVERT(char(10), TCS.CreationTime, 120),'') as CreationTime2
		 , ISNULL(CONVERT(char(10), TI.LastUpdated, 120),'') as LastUpdated
		 , ISNULL(TCLS.ExtFunc, 0) as ExtFunc
		 , ISNULL(TCS.CurTask,'') as CurTask
		 , TPJ.Creator
		 , ISNULL(TPJ.AuthorID,'') as pjtAuthorId
		 , TPJ.Status As CSRStatusCode
		 , ISNULL(TM2.Name,'') + Case When ISNULL(TM2.NameEN,'') != '' Then '(' + ISNULL(TM2.NameEN,'') + ')' Else '' End As CreatorName
		 , PT1.Name As csrName
		 , PT2.Name As PjtName
		 , PT2.Name As parentPjtName
		 , ISNULL(TIT.Icon, 'img_job.png') ItemTypeImg
		 , TCS.Version
		 , ISNULL(CONVERT(char(10),TCS.ValidFrom, 120),'') as ValidFrom
		 , TCS.ChangeType AS ChangeTypeCode
		 , ISNULL(TCS.WFInstanceID,'') AS WFInstanceID
		 , ISNULL(TWI.Status,'0') AS wfStatus
		 , TDWF.Name AS WFStatusName	
		 , TCS.CheckInOption
		 , TCS.SRID
		 , TI.ClassCode AS ItemClassCode
		FROM XBOLTADM.TB_CHANGE_SET TCS
			Left Outer Join XBOLTADM.TB_ITEM TI
			on TCS.ItemID = TI.ItemID			
			Left Outer Join XBOLTADM.TB_ITEM_ATTR TIA
			on TCS.ItemID = TIA.ItemID AND TIA.AttrTypeCode = 'AT00001' AND TIA.LanguageID = #{languageID}
			Left Outer Join XBOLTADM.TB_MEMBER TM
			on TCS.AuthorID = TM.MemberID
			Left Outer Join XBOLTADM.TB_TEAM_TXT TTT
			on TCS.AuthorTeamID = TTT.TeamID AND TTT.LanguageID = #{languageID}
			Left Outer Join XBOLTADM.TB_DICTIONARY TDT 
			on TCS.ItemTypeCode = TDT.TypeCode AND TDT.LanguageID = #{languageID}
			Left Outer Join XBOLTADM.TB_DICTIONARY TD 
			on TCS.ItemClassCode = TD.TypeCode AND TD.LanguageID = #{languageID}
			Left outer Join XBOLTADM.TB_DICTIONARY TDS
			on TCS.Status = TDS.TypeCode AND TDS.Category = 'CNGSTS'  AND TDS.LanguageID = #{languageID}
			Left outer Join XBOLTADM.TB_DICTIONARY TDIS
			on TI.Status = TDIS.TypeCode AND TDIS.Category = 'ITMSTS'  AND TDIS.LanguageID = #{languageID}
			Left outer Join XBOLTADM.TB_DICTIONARY TRS
			on TCS.Reason = TRS.TypeCode AND TRS.Category = 'CR'  AND TRS.LanguageID = #{languageID}
			Left outer Join XBOLTADM.TB_DICTIONARY TCTS
			on TCS.ChangeType = TCTS.TypeCode AND TCTS.Category = 'CNGT1'  AND TCTS.LanguageID = #{languageID}
			Left outer Join XBOLTADM.TB_ITEM_CLASS TCLS on TI.ClassCode = TCLS.ItemClassCode
			Left outer Join XBOLTADM.TB_PROJECT TPJ on TCS.ProjectID = TPJ.ProjectID
			Left Outer Join XBOLTADM.TB_MEMBER TM2 on TPJ.Creator = TM2.MemberID
			Left Outer Join XBOLTADM.TB_PROJECT_TXT PT1 on TCS.ProjectID = PT1.ProjectID AND PT1.LanguageID = #{languageID}
			Left Outer Join XBOLTADM.TB_PROJECT_TXT PT2 on TPJ.RefPjtID = PT2.ProjectID AND PT2.LanguageID = #{languageID}
			Left Outer Join XBOLTADM.TB_ITEM_TYPE TIT ON TI.ItemTypeCode = TIT.ItemTypeCode
			
			Left Outer JOIN XBOLTADM.TB_ITEM_DIM TID ON TI.ItemID = TID.ItemID 
			
			Left Outer JOIN XBOLTADM.TB_WF_INST TWI ON TCS.WFInstanceID = TWI.WFInstanceID 
			Left outer Join XBOLTADM.TB_DICTIONARY TDWF ON TWI.Status = TDWF.TypeCode AND TDWF.Category = 'APRVSTS'  AND TDWF.LanguageID = #{languageID}
		 WHERE NOT EXISTS ( SELECT 1 
						    FROM XBOLTADM.TB_ITEM TIM  
							WHERE TIM.ItemID = TI.ItemID AND TIM.Deleted = '1'AND TIM.Status  = 'NEW1'AND TIM.CategoryCode = 'OJ')
	  	       
			
				AND TCS.WFInstanceID = #{wfInstanceID}
			
			
				AND TCS.ItemTypeCode = #{ItemTypeCode}
			
			
				AND TCS.ChangeType = #{changeClassList}
			
			
				AND TCS.ChangeType != #{nChangeType}
			
			
				AND TCS.Status = #{Status}
			
			
				AND TCS.Reason = #{Reason}
			
			
				AND TCS.AuthorTeamID = #{AuthorTeamID}
			
			
				AND TIA.PlainText Like '%'+#{searchValue}+'%'
			
			
				AND TCS.ItemID = #{s_itemID}
			
			
				AND TCS.PJTCategory = #{category}
			
			
				AND TCS.Version = #{version}
			
				
				
					AND TID.DimValueID = #{DimValueID}	AND TID.DimTypeID  = #{DimTypeID}
					
					
			
				
					AND TCS.ProjectID IN(Select ProjectID From XBOLTADM.TB_PROJECT Where RefPGID = #{refID} And ProjectType = 'CSR' )
				
				
					AND TCS.ProjectID IN(Select ProjectID From XBOLTADM.TB_PROJECT Where RefPjtID = #{refID} And ProjectType = 'CSR' )
				
			
			
				AND TCS.ProjectID IN(Select ProjectID From XBOLTADM.TB_PROJECT Where RefPjtID = #{projectID} And ProjectType = 'CSR' )
			
			
				AND TPJ.RefPjtID = #{parentPjtID}
			
			
				AND TCS.ProjectID = #{csrID}
			
			
				AND TCS.AuthorID = #{AuthorID}
			
			
				AND TCS.AuthorID = #{sessionUserId}
			
			
				AND TCS.ChangeSetID = #{ChangeSetID}
			
			
				AND TCLS.ItemClassCode = #{classCode}
			
			
				AND  TCS.CreationTime >=   #{reqStartDt} AND TCS.CreationTime < #{reqEndDt}
			  
			
				AND TCS.CompletionDT >= #{clsStartDt} AND TCS.CompletionDT < #{clsEndDt}
			  
			
				AND TCS.ValidFrom >= #{vfStartDt} AND TCS.ValidFrom < #{vfEndDt}
			  
			
				AND TI.LastUpdated >=  #{ltStartDt} AND TI.LastUpdated < #{ltEndDt}
			  
			
				AND TM.Name like '%'+#{authorName} +'%'
			
			
				AND TCS.ApproveDate >= #{apStartDt} AND TCS.ApproveDate < #{apEndDt}
			  
			
				AND TCS.ChangeSetID In 
			  (SELECT Max(ChangeSetID)  as ChangeSetID   FROM XBOLTADM.TB_CHANGE_SET   Where Status = #{csStatus} Group By ItemID)
		 		
		 	
				AND TCS.CRID = #{scrID}
			
		)TC
		
			
				TC.RNUM BETWEEN ((${pageNo}-1)*${LIST_PAGE_SCALE}  + 1) AND (${pageNo}*${LIST_PAGE_SCALE})
			
			
				AND ItemID NOT IN (select ItemID FROM XBOLTADM.TB_ITEM_DIM WHERE DimTypeID = #{DimTypeID})
			
		
		ORDER BY RNUM ASC

	  
	    WITH TargetList AS (
	        SELECT 
	                    
	                 TOP 5 
	                 TOP 1000 
	            
	            TCS.ChangeSetID,
	            TCS.ItemID,
	            TCS.ProjectID,
	            TI.AuthorID AS AuthorID, 
	            TCS.ItemClassCode,
	            TCS.Status AS StatusCode,
	            TCS.ChangeType AS ChangeTypeCode,
	            
	                
	                    Row_Number() OVER(ORDER BY TCS.ValidFrom DESC) as RNUM 
	                
	                
	                    Row_Number() OVER(ORDER BY TI.LastUpdated DESC) as RNUM 
	                
	            
	        FROM XBOLTADM.TB_CHANGE_SET TCS WITH (NOLOCK)
	        INNER JOIN XBOLTADM.TB_ITEM TI WITH (NOLOCK) ON TCS.ItemID = TI.ItemID AND TCS.ChangeSetID = TI.CurChangeSet
	        INNER JOIN XBOLTADM.TB_ITEM_CLASS TCLS WITH (NOLOCK) ON TI.ClassCode = TCLS.ItemClassCode
	        

	        
	            LEFT OUTER JOIN XBOLTADM.TB_TEAM_TXT TTT_S ON TI.OwnerTeamID = TTT_S.TeamID AND TTT_S.LanguageID = #{languageID}
	        
	        
	            LEFT OUTER JOIN XBOLTADM.TB_MEMBER TM_S ON TCS.AuthorID = TM_S.MemberID
	        
	        
	            LEFT OUTER JOIN XBOLTADM.TB_PROJECT TPJ_S ON TCS.ProjectID = TPJ_S.ProjectID
	        
	        
	            LEFT OUTER JOIN XBOLTADM.TB_ITEM_DIM TID_S ON TI.ItemID = TID_S.ItemID
	        
	
	        
	        
	            TI.ItemID NOT IN (SELECT ItemID FROM XBOLTADM.TB_ITEM WHERE Deleted = '1' AND Status = 'NEW1' AND CategoryCode = 'OJ')
	            AND TI.ItemID IN (SELECT ToItemID FROM XBOLTADM.TB_ITEM WHERE CategoryCode = 'ST1')
	            
	             AND TI.CategoryCode = 'OJ' 
	             AND TI.Deleted = 0 
	             AND TCS.ItemTypeCode = #{ItemTypeCode} 
	             AND TCS.Status = #{Status} 
	             AND TCS.Reason = #{Reason} 
	             AND TCS.AuthorTeamID = #{AuthorTeamID} 
	            
	        
	            
	                AND TI.ClassCode IN 
	                
	                    #{item}
	                
	            
	
	             AND TCS.AuthorTeamID = #{sessionTeamId} 
	             AND TI.Identifier Like '%' + #{identifier} + '%' 
	             AND TI.CompanyID = #{Company} 
	             AND TCS.ItemID = #{s_itemID} 
	             AND TCS.PJTCategory = #{category} 
	             AND TCS.Version = #{version} 
	        
	             
	                AND TTT_S.Name LIKE '%' + #{authorTeamName} + '%' 
	            
	             
	                AND TM_S.Name LIKE '%' + #{authorName} + '%' 
	            
	
	     
	            
	                AND EXISTS (SELECT 1 FROM XBOLTADM.TB_ITEM_ATTR WHERE ItemID = TI.ItemID AND AttrTypeCode = 'AT00001' AND PlainText Like '%' + #{searchValue} + '%')
	            
	           
	             AND CONVERT(char(8),TCS.CreationTime, 112) BETWEEN #{reqStartDt} AND #{reqEndDt} 
	             AND CONVERT(char(8),TCS.CompletionDT, 112) BETWEEN #{clsStartDt} AND #{clsEndDt} 
	             AND CONVERT(char(8),TCS.ValidFrom, 112) BETWEEN #{vfStartDt} AND #{vfEndDt} 
	             AND CONVERT(char(8),TI.LastUpdated, 112) BETWEEN #{modStartDt} AND #{modEndDt} 
	             AND TPJ_S.RefPjtID = #{parentPjtID} 
	
	            
	                AND TID_S.DimTypeID = #{DimTypeID}
	                
	                    AND TID_S.DimValueID IN #{item}
	                
	            
	            
                AND EXISTS (
                    SELECT 1 FROM XBOLTADM.TB_TEAM_ROLE S1
                    INNER JOIN XBOLTADM.TB_TEAM_TXT S2 ON S1.TeamID = S2.TeamID
                    WHERE S1.ItemID = TI.ItemID AND S1.Assigned = 1 AND S2.Name LIKE '%' + #{relatedTeamName} + '%' AND S2.LanguageID = #{languageID}
                )
               
	            
	                 AND TCS.ProjectID IN (Select ProjectID From XBOLTADM.TB_PROJECT Where RefPGID = #{refID} And ProjectType = 'CSR' ) 
	                 AND TCS.ProjectID IN (Select ProjectID From XBOLTADM.TB_PROJECT Where RefPjtID = #{refID} And ProjectType = 'CSR' ) 
	            
	            AND TCS.ProjectID IN (Select ProjectID From XBOLTADM.TB_PROJECT Where RefPjtID = #{projectID} And ProjectType = 'CSR' ) 
	             AND TPJ.RefPjtID = #{parentPjtID} 
	            
	                AND TCS.ProjectID IN #{item}
	            
	             AND TCS.AuthorID = #{AuthorID}
	             AND TCS.ChangeSetID = #{ChangeSetID} 
	            
	                AND TCLS.ItemClassCode IN #{item}
	            
	        
	        
	    )

	    
	    , RelatedTeamListAgg AS (
	        SELECT S1.ItemID, STRING_AGG(CAST(ISNULL(S2.Name, '') AS varchar), ', ') AS RelatedTeamList
	        FROM XBOLTADM.TB_TEAM_ROLE S1 WITH (NOLOCK)
	        LEFT JOIN XBOLTADM.TB_TEAM_TXT S2 WITH (NOLOCK) ON S2.TeamID = S1.TeamID AND S2.LanguageID = #{languageID}
	        WHERE S1.Assigned = 1 AND S1.ItemID IN (SELECT ItemID FROM TargetList)
	        GROUP BY S1.ItemID
	    )
	    
	
	    SELECT 
	        TL.RNUM, 0 AS CHK, TL.ChangeSetID, TL.ProjectID, TI.Identifier, TIA.PlainText AS ItemName,
	        TL.ItemID, TCTS.Name AS ChangeType, TD.Name AS ClassCodeName, TL.ItemClassCode, TRS.Name AS Reason,
	        TCS.Description, 
	        TI.OwnerTeamID AS AuthorTeamID, 
	        ISNULL(TTT.Name,'') AS AuthorTeamName,
	        ISNULL(TTT.TeamCode,'') AS AuthorTeamCode, 
	        TL.AuthorID, 
	        TM.Name As AuthorName,
	        ISNULL(CONVERT(char(10),TCS.CreationTime, 120),'') as CreationTime,
	        ISNULL(CONVERT(char(10),TCS.ApproveDate, 120),'') as ApproveDate,
	        ISNULL(CONVERT(char(10),TCS.CompletionDT, 120),'') as CompletionDT, 
	        CASE ISNULL(TCS.CompletionDT, '') WHEN '' THEN '' ELSE '~' END CompletionDTYNMark,
	        TL.StatusCode, TDS.Name AS StatusName, TI.Status AS ItemStatus,
	        ISNULL(CONVERT(char(10), TI.LastUpdated, 120),'') as LastUpdated,
	        ISNULL(TCLS.ExtFunc, 0) as ExtFunc, ISNULL(TCS.CurTask,'') as CurTask,
	        TPJ.Creator, PT1.Name As csrName, PT2.Name As PjtName,
	        ISNULL(TIT.Icon, 'img_job.png') ItemTypeImg, TCS.Version,
	        ISNULL(CONVERT(char(10),TCS.ValidFrom, 120),'') as ValidFrom,
	        TL.ChangeTypeCode, TDCT.Name AS ChangeTypeName, TCLS.CheckInOption, ISNULL(TCS.WFInstanceID, '') AS WFInstanceID
	        
	        , ISNULL(RT.RelatedTeamList, '') AS RelatedTeamNameList
	        
	    FROM TargetList TL
	    JOIN XBOLTADM.TB_CHANGE_SET TCS WITH (NOLOCK) ON TL.ChangeSetID = TCS.ChangeSetID
	    LEFT OUTER JOIN XBOLTADM.TB_ITEM TI WITH (NOLOCK) ON TL.ItemID = TI.ItemID
	    LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA WITH (NOLOCK) ON TL.ItemID = TIA.ItemID AND TIA.AttrTypeCode = 'AT00001' AND TIA.LanguageID = #{languageID}
	    LEFT OUTER JOIN XBOLTADM.TB_MEMBER TM WITH (NOLOCK) ON TL.AuthorID = TM.MemberID
	    
	
	    LEFT OUTER JOIN XBOLTADM.TB_TEAM_TXT TTT WITH (NOLOCK) ON TI.OwnerTeamID = TTT.TeamID AND TTT.LanguageID = #{languageID}
	    
	    LEFT OUTER JOIN XBOLTADM.TB_DICTIONARY TD WITH (NOLOCK) ON TL.ItemClassCode = TD.TypeCode AND TD.LanguageID = #{languageID}
	    LEFT OUTER JOIN XBOLTADM.TB_DICTIONARY TDS WITH (NOLOCK) ON TL.StatusCode = TDS.TypeCode AND TDS.Category = 'CNGSTS' AND TDS.LanguageID = #{languageID}
	    LEFT OUTER JOIN XBOLTADM.TB_DICTIONARY TDCT WITH (NOLOCK) ON TL.ChangeTypeCode = TDCT.TypeCode AND TDCT.Category = 'CNGT1' AND TDCT.LanguageID = #{languageID}
	    LEFT OUTER JOIN XBOLTADM.TB_DICTIONARY TRS ON TCS.Reason = TRS.TypeCode AND TRS.Category = 'CR' AND TRS.LanguageID = #{languageID}
	    LEFT OUTER JOIN XBOLTADM.TB_DICTIONARY TCTS WITH (NOLOCK) ON TL.ChangeTypeCode = TCTS.TypeCode AND TCTS.Category = 'CNGT1' AND TCTS.LanguageID = #{languageID}
	    LEFT OUTER JOIN XBOLTADM.TB_ITEM_CLASS TCLS WITH (NOLOCK) ON TI.ClassCode = TCLS.ItemClassCode
	    LEFT OUTER JOIN XBOLTADM.TB_PROJECT TPJ WITH (NOLOCK) ON TL.ProjectID = TPJ.ProjectID
	    LEFT OUTER JOIN XBOLTADM.TB_PROJECT_TXT PT1 WITH (NOLOCK) ON TL.ProjectID = PT1.ProjectID AND PT1.LanguageID = #{languageID}
	    LEFT OUTER JOIN XBOLTADM.TB_PROJECT_TXT PT2 WITH (NOLOCK) ON TPJ.RefPjtID = PT2.ProjectID AND PT2.LanguageID = #{languageID}
	    LEFT OUTER JOIN XBOLTADM.TB_ITEM_TYPE TIT WITH (NOLOCK) ON TI.ItemTypeCode = TIT.ItemTypeCode
	    
	    
	    LEFT OUTER JOIN RelatedTeamListAgg RT ON TL.ItemID = RT.ItemID
	    
	    
	        
	            AND TL.RNUM BETWEEN ((CAST(#{pageNo} AS INT) - 1) * CAST(#{pageRow} AS INT) + 1) AND (CAST(#{pageNo} AS INT) * CAST(#{pageRow} AS INT))
	        
	        
	            AND TL.ItemID NOT IN (select ItemID FROM XBOLTADM.TB_ITEM_DIM WHERE DimTypeID = #{DimTypeID})
	        
	    
	    ORDER BY TL.RNUM ASC

  SELECT COUNT(1) AS CNT
  FROM XBOLTADM.TB_CHANGE_SET TCS
    Left Outer Join XBOLTADM.TB_ITEM TI on TCS.ItemID = TI.ItemID
    Left Outer Join XBOLTADM.TB_ITEM_ATTR TIA
      on TCS.ItemID = TIA.ItemID
     AND TIA.AttrTypeCode = 'AT00001'
     AND TIA.LanguageID = #{languageID}
    Left Outer Join XBOLTADM.TB_MEMBER TM on TCS.AuthorID = TM.MemberID
    Left Outer Join XBOLTADM.TB_TEAM_TXT TTT on TCS.AuthorTeamID = TTT.TeamID AND TTT.LanguageID = #{languageID}
    Left Outer Join XBOLTADM.TB_ITEM_CLASS TCLS on TI.ClassCode = TCLS.ItemClassCode
    Left outer Join XBOLTADM.TB_PROJECT TPJ on TCS.ProjectID = TPJ.ProjectID

	
    Left Outer Join XBOLTADM.TB_PROJECT_TXT PT1 on TCS.ProjectID = PT1.ProjectID AND PT1.LanguageID = #{languageID}
    Left Outer Join XBOLTADM.TB_PROJECT_TXT PT2 on TPJ.RefPjtID = PT2.ProjectID AND PT2.LanguageID = #{languageID}

  WHERE TI.Identifier IS NOT NULL
    AND NOT EXISTS (
      SELECT 1
      FROM XBOLTADM.TB_ITEM X
      WHERE X.ItemID = TI.ItemID
        AND X.Deleted = '1'
        AND X.Status = 'NEW1'
    )

    
      AND TI.CategoryCode = 'OJ'
    

    
      AND TCS.ItemTypeCode = #{ItemTypeCode}
    

    
      AND TCS.ChangeType = #{changeType}
    

    
      AND TCS.Status = #{Status}
    

    
      AND TCS.Reason = #{Reason}
    

    
      AND TCS.AuthorTeamID = #{AuthorTeamID}
    

    
      AND TI.ClassCode IN ( ${classCodeList} )
    

    
      AND TCS.AuthorTeamID = #{sessionTeamId}
    

    
      AND TIA.PlainText Like '%'+#{searchValue}+'%'
    

    
      AND TCS.ItemID = #{s_itemID}
    

    
      AND TCS.PJTCategory = #{category}
    

    
      AND TCS.Version = #{version}
    

    
      AND EXISTS (
        SELECT 1
        FROM XBOLTADM.TB_ITEM_DIM TID
        WHERE TID.ItemID = TI.ItemID
          AND TID.DimTypeID = #{DimTypeID}
        
          AND TID.DimValueID IN
          
            #{item}
          
        
      )
    

    
      
        AND TCS.ProjectID IN (
          Select ProjectID
          From XBOLTADM.TB_PROJECT
          Where RefPGID = #{refID}
            And ProjectType = 'CSR'
        )
      
      
        AND TCS.ProjectID IN (
          Select ProjectID
          From XBOLTADM.TB_PROJECT
          Where RefPjtID = #{refID}
            And ProjectType = 'CSR'
        )
      
    

    
      AND TCS.ProjectID IN(
        Select ProjectID
        From XBOLTADM.TB_PROJECT
        Where RefPjtID = #{projectID}
          And ProjectType = 'CSR'
      )
    

    
      AND TPJ.RefPjtID = #{parentPjtID}
    

    
      AND TCS.ProjectID IN (
        
          #{item}
        
      )
    

    
      AND TCS.AuthorID = #{AuthorID}
    

    
      AND TCS.ChangeSetID = #{ChangeSetID}
    

    
      AND TCLS.ItemClassCode IN (
        
          #{item}
        
      )
    

    
      AND TCS.CreationTime >= #{reqStartDt}
      AND TCS.CreationTime < DATEADD(DAY, 1, #{reqEndDt})
    

    
      AND TCS.CompletionDT >= #{clsStartDt}
      AND TCS.CompletionDT < DATEADD(DAY, 1, #{clsEndDt})
    

    
      AND TCS.ValidFrom >= #{vfStartDt}
      AND TCS.ValidFrom < DATEADD(DAY, 1, #{vfEndDt})
    

    
      AND TM.Name like '%'+#{authorName} +'%'
    

    
      AND TTT.Name like '%'+#{authorTeamName} +'%'
    

    
      AND TI.CompanyID = #{Company}
    

    
      AND TI.LastUpdated >= #{modStartDt}
      AND TI.LastUpdated < DATEADD(DAY, 1, #{modEndDt})

SELECT
TOP ${top}
Row_Number()OVER(ORDER BY TCS.CreationTime DESC) AS RNUM , 0 AS CHK , TCS.ChangeSetID , TCS.ItemID , TD.Name AS TypeName , TCD.Name AS ClassName , TIA.PlainText AS ItemName , ISNULL(TM.NAME , TCS.AuthorName) AS AuthorName , ISNULL(TAM.Name , '') AS ApproveName , CONVERT(varchar(14),TCS.CreationTime,111) as CreationTime , CASE WHEN TCS.Status = 'APRV1' THEN ISNULL(CONVERT(varchar(14),TCS.ApproveDate,111) ,'') ELSE '' END ApprovTime , TSD.Name AS StatusName , XBOLTADM.fn_getMyAbsPathForList(TCS.ItemID, #{languageID}) AS Path , TRD.Name AS ReasonName , TID.Name AS ItemStatus , TCS.Status FROM XBOLTADM.TB_CHANGE_SET TCS
LEFT OUTER JOIN XBOLTADM.TB_DICTIONARY TID ON TID.LanguageID = #{languageID} AND TCS.ChangeType = TID.TypeCode AND TID.Category = 'CNGT1'
Left Outer Join XBOLTADM.TB_DICTIONARY TD on TCS.ItemTypeCode = TD.TypeCode AND TD.LanguageID = #{languageID}
Left Outer Join XBOLTADM.TB_DICTIONARY TCD on TCS.ItemClassCode = TCD.TypeCode AND TCD.LanguageID = #{languageID}
Left Outer Join XBOLTADM.TB_DICTIONARY TSD on TCS.Status = TSD.TypeCode AND TSD.LanguageID = #{languageID} AND TSD.Category = 'CNGSTS' Left Outer Join XBOLTADM.TB_DICTIONARY TRD on TCS.Reason = TRD.TypeCode AND TRD.LanguageID = #{languageID} AND TRD.Category = 'CR' Left Outer Join XBOLTADM.TB_MEMBER TM on TCS.AuthorID = TM.MemberID Left Outer Join XBOLTADM.TB_MEMBER TAM on TCS.Approver = TAM.MemberID
Left Outer Join XBOLTADM.TB_ITEM_ATTR TIA on TCS.ItemID = TIA.ItemID AND TIA.LanguageID = #{languageID} AND TIA.AttrTypeCode ='AT00001'
TCS.ProjectID in ( SELECT ProjectID FROM XBOLTADM.TB_PROJECT WHERE PJCategory = #{Category} )
AND TCS.ProjectID = #{s_itemID}
AND TCS.ItemTypeCode = #{TypeCode}
AND TCS.Status = #{Status}
AND TCS.Reason = #{Reason}
AND TCS.ChangeType = #{Type}
AND TCS.Approver = #{apprID}
AND TCS.AuthorID = #{viewID}
ORDER BY TCS.CreationTime Desc

