SELECT Row_Number()OVER(ORDER BY CAST(T1.Version AS FLOAT) ASC, T1.ChangeSetID ASC) as RNUM ,T1.ItemID , 0 AS CHK , T1.ProjectID , T2.Name AS CSRName , ISNULL(T12.PlainText, T13.PlainText) As ItemName , T1.ChangeSetID , (SELECT Name FROM XBOLTADM.TB_PROJECT_TXT WHERE ProjectID = T10.RefPjtID AND LanguageID = #{languageID}) + '/' + T2.Name AS ProjectName , ISNULL(T3.Name,'') + Case When ISNULL(T3.NameEN,'') != '' Then '(' + ISNULL(T3.NameEN,'') + ')' Else '' End As RequestUserName , T1.AuthorID As RequestUserId , ISNULL(CONVERT(char(10), T1.CreationTime, 111),'-') as RequestDate , ISNULL(T4.Name,'-') + Case When ISNULL(T4.NameEN,'') != '' Then '(' + ISNULL(T4.NameEN,'') + ')' Else '' End As ApprovedUserName , ISNULL(CONVERT(char(10), T1.Approver), '-') As ApprovedUserId , ISNULL(CONVERT(char(10), T1.ApproveDate, 111),'-') as ApproveDate , T5.Name As ChangeSts , T1.Status As ChangeStsCode , T6.Name As ChangeType , T7.Name As ChangeReason , ISNULL(T1.Description,'') AS Description , T8.Name As RequestUserTeamName , ISNULL(T9.Name, '-') As ApproverTeamName , (SELECT ProjectCode FROM XBOLTADM.TB_PROJECT WHERE ProjectID = T1.ProjectID) AS CSRID , (SELECT Name FROM XBOLTADM.TB_PROJECT_TXT WHERE ProjectID = T10.RefPjtID AND LanguageID = #{languageID}) AS ParentName , Case When ISNULL(TIC.ExtFunc, 0) = 1 Then 'btn_view.png' Else 'blank.png' End ImgTaskInfoView , 'btn_view.png' As ImgPjtInfoView , T10.RefPjtID As ParentID , T1.Version , ISNULL(CONVERT(char(10), T1.ValidFrom, 111),'-') as ValidFromDate , ISNULL(CONVERT(char(10), T1.CompletionDT, 111),'-') as CompletionDate ,T1.AuthorTeamID ,ISNULL(T11.Name, '') as RequestUserTeamName ,ISNULL(T14.Identifier, '') as Identifier ,T1.ChangeType AS ChangeTypeCode FROM XBOLTADM.TB_CHANGE_SET T1 Left Outer Join XBOLTADM.TB_PROJECT_TXT T2 on T1.ProjectID = T2.ProjectID AND T2.LanguageID = #{languageID} Left Outer Join XBOLTADM.TB_MEMBER T3 on T1.AuthorID = T3.MemberID Left Outer Join XBOLTADM.TB_MEMBER T4 on T1.Approver = T4.MemberID Left Outer Join XBOLTADM.TB_DICTIONARY T5 on T1.Status = T5.TypeCode AND T5.LanguageID = #{languageID} AND T5.Category = 'CNGSTS' Left Outer Join XBOLTADM.TB_DICTIONARY T6 on T1.ChangeType = T6.TypeCode AND T6.LanguageID = #{languageID} AND T6.Category = 'CNGT1' Left Outer Join XBOLTADM.TB_DICTIONARY T7 on T1.Reason = T7.TypeCode AND T7.LanguageID = #{languageID} AND T7.Category = 'CR' LEFT OUTER JOIN XBOLTADM.TB_TEAM_TXT T8 ON T8.LanguageID = #{languageID} AND T3.TeamID = T8.TeamID LEFT OUTER JOIN XBOLTADM.TB_TEAM_TXT T9 ON T9.LanguageID = #{languageID} AND T4.TeamID = T9.TeamID Left Outer Join XBOLTADM.TB_PROJECT T10 on T1.ProjectID = T10.ProjectID Left Outer Join XBOLTADM.TB_ITEM_CLASS TIC ON TIC.ItemClassCode = T1.ItemClassCode Left Outer Join XBOLTADM.TB_TEAM_TXT T11 ON T11.TeamID = T1.AuthorTeamID and T11.LanguageID = #{languageID} Left Outer Join XBOLTADM.TB_ITEM_ATTR_REV T12 ON T1.ItemID = T12.ItemID and T1.ChangeSetID = T12.ChangeSetID and T12.LanguageID = #{languageID} and T12.AttrTypeCode = 'AT00001' Left Outer Join XBOLTADM.TB_ITEM_ATTR T13 ON T1.ItemID = T13.ItemID and T13.LanguageID = #{languageID} and T13.AttrTypeCode = 'AT00001' Left Outer Join XBOLTADM.TB_ITEM T14 ON T1.ItemID = T14.ItemID
AND T1.ItemID = #{s_itemID}
AND T1.ChangeSetID = #{changeSetID}
AND T1.ChangeSetID != #{notChangeSetID}
ORDER BY CAST(T1.Version AS FLOAT) DESC, T1.ChangeSetID DESC

