SELECT TCS.ChangeSetID , TCS.ProjectID , TCS.PJTCategory , TCS.Description , RTRIM(TCS.ChangeType) AS ChangeType , TCS.Reason , RTRIM(TCS.Status) AS Status , TD.Name AS ChangeTypeNM , TCS.ItemID , TCS.Version , ISNULL(CONVERT(char(10), TCS.CreationTime, 111),'') AS CreationTime , Case When ISNULL(TM.NameEN,'') != '' Then ISNULL(TM.Name,'')+'('+ISNULL(TM.NameEN,'')+')' ELSE ISNULL(TM.NAME,'') END AS AuthorName , TM.Name AS AuthorNM , TEAM.Name AS AuthorTeamName , CMPNY.Name As CompanyName , CONVERT(VARCHAR, TCS.CompletionDT, 111) As CompletionDT , TCS.AuthorID , CONVERT(VARCHAR, TCS.ApproveDate, 111) As ApproveDate , TP.EndDate CSREndDate , TCS.WFInstanceID , CASE WHEN TWI.CreationTime = TWI.LastUpdated Then 'N' else 'Y' End as WFInstanceON FROM XBOLTADM.TB_CHANGE_SET TCS Left Outer Join XBOLTADM.TB_MEMBER TM ON TM.MemberID = TCS.AuthorID Left Outer Join XBOLTADM.TB_TEAM_TXT TEAM ON TEAM.TeamID = TCS.AuthorTeamID And TEAM.LanguageID = #{languageID} Left Outer Join XBOLTADM.TB_TEAM_TXT CMPNY ON CMPNY.TeamID = TCS.CompanyID And CMPNY.LanguageID = #{languageID} Left Outer Join XBOLTADM.TB_DICTIONARY TD ON TD.TypeCode = TCS.ChangeType And TD.Category = 'CNGT1' and TD.LanguageID = #{languageID} Left Outer Join XBOLTADM.TB_PROJECT TP ON TP.ProjectID = TCS.ProjectID Left Outer Join XBOLTADM.TB_WF_INST TWI ON TCS.WFInstanceID = TWI.WFInstanceID
AND ( TCS.ItemID = #{s_itemID} or TCS.ItemID = #{parentItemID} )
AND TCS.ChangeSetID = #{ChangeSetID}
AND TCS.ProjectID = #{ProjectID}
AND TCS.Status = #{Status}

